class Solution:
    def evalRPN(self, tokens: List[str]) -> int:
        # Initialize Stack to hold operands and intermediate results
        stack = []

        # Scan each token left to right
        for char in tokens:
            # Addition — pop two, add, push. Order doesn't matter 
            if char == "+":
                stack.append(stack.pop() + stack.pop())
            # Subtraction - Pop a (right operand) first, then b (left operand). Push b - a —> order matters!
            elif char == "-":
                a, b = stack.pop(), stack.pop()
                stack.append(b - a)
            # Multiplication — pop two, multiply, push. Order doesn't matter 
            elif char == "*":
                stack.append(stack.pop() * stack.pop())
            # Division - Pop a (right/divisor) first, then b (left/dividend). Push int(b / a) — truncates toward zero
            elif char == "/":
                a, b = stack.pop(), stack.pop()
                stack.append(int(b/a))
            # Not an operator → it's a number → push as int
            else:
                stack.append(int(char))
        # One value left — the result
        return stack[0]

        # TC: O(n) -> Single pass through n tokens; each push/pop is O(1)
        # SC: O(n) -> Stack holds up to O(n) operands (e.g. all numbers before any operator)

        # Solution Description: Reverse Polish Notation places operators after their operands, which makes it perfectly suited to a stack. Scan the tokens left to right. Every number gets pushed onto the stack. When an operator appears, pop the top two numbers, apply the operator, and push the result back — that result becomes an operand for a later operation. After processing all tokens, exactly one number remains on the stack: the final answer. The one subtlety is operand order — since the stack is LIFO, the first value popped is the right-hand operand, which matters for subtraction and division.                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                Reverse Polish Notation places operators after their operands, which makes it perfectly suited to a stack. Scan the tokens left to right. Every number gets pushed onto the stack. When an operator appears, pop the top two numbers, apply the operator, and push the result back — that result becomes an operand for a later operation. After processing all tokens, exactly one number remains on the stack: the final answer. The one subtlety is operand order — since the stack is LIFO, the first value popped is the right-hand operand, which matters for subtraction and division.

        # why b - a and not a - b -> The stack is LIFO, so the first value you pop is the one that was pushed last — which is the right operand. - and / are not commutative, so order is critical.
        # Why int(b / a) and not b // a -> The problem says division truncates toward zero, but Python's // truncates toward negative infinity. So we must use int(b / a) — do true (float) division, then int() chops off the decimal toward zero. Using // would give wrong answers on negative results.